{
  "command": "psql -h 127.0.0.1 -U user -d bookreview_db -c \"SELECT categories FROM books_info LIMIT 5\"",
  "description": "Check categories format"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT review_time FROM review LIMIT 5\"",
  "description": "Check review_time format"
}

{
  "command": "psql -h 127.0.0.1 -U user -d bookreview_db -t -A -F\"|\" -c \"SELECT book_id, title FROM books_info WHERE categories LIKE '%Children''s Books%'\" > /tmp/children_books.txt && wc -l /tmp/children_books.txt",
  "description": "Get all Children's Books"
}

{
  "command": "ids=$(psql -h 127.0.0.1 -U user -d bookreview_db -t -A -c \"SELECT string_agg(quote_literal(book_id), ',') FROM books_info WHERE categories LIKE '%Children''s Books%'\")\necho \"$ids\" | head -c 500\necho \"\"\nsqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT purchase_id, AVG(rating) as avg_rating, COUNT(*) as cnt FROM review WHERE review_time >= '2020-01-01' AND purchase_id IN ($ids) GROUP BY purchase_id HAVING AVG(rating) >= 4.5\"",
  "description": "Get avg ratings from 2020 for Children's Books"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT purchase_id, AVG(rating) as avg_rating, COUNT(*) as cnt FROM review WHERE review_time >= '2020-01-01' AND purchase_id IN ('bookid_4','bookid_14','bookid_32','bookid_40','bookid_48','bookid_52','bookid_54','bookid_55','bookid_57','bookid_96','bookid_99','bookid_108','bookid_111','bookid_116','bookid_120','bookid_124','bookid_130','bookid_132','bookid_145','bookid_146','bookid_149','bookid_152','bookid_158','bookid_163','bookid_170') GROUP BY purchase_id ORDER BY avg_rating DESC\"",
  "description": "Get all avg ratings"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT purchase_id, rating, review_time FROM review WHERE purchase_id = 'bookid_4' LIMIT 10\"",
  "description": "Check reviews for one book"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT DISTINCT purchase_id FROM review LIMIT 20\"",
  "description": "Check purchase_id format"
}

{
  "command": "sqlite3 '/workspace/DataAgentBench/query_bookreview/query_dataset/review_query.db' \"SELECT purchase_id, AVG(rating) as avg_rating, COUNT(*) as cnt FROM review WHERE review_time >= '2020-01-01' AND purchase_id IN ('purchaseid_4','purchaseid_14','purchaseid_32','purchaseid_40','purchaseid_48','purchaseid_52','purchaseid_54','purchaseid_55','purchaseid_57','purchaseid_96','purchaseid_99','purchaseid_108','purchaseid_111','purchaseid_116','purchaseid_120','purchaseid_124','purchaseid_130','purchaseid_132','purchaseid_145','purchaseid_146','purchaseid_149','purchaseid_152','purchaseid_158','purchaseid_163','purchaseid_170') GROUP BY purchase_id HAVING AVG(rating) >= 4.5 ORDER BY avg_rating DESC\"",
  "description": "Get avg ratings from 2020 onwards"
}
